import React, { useState } from "react";
import PopupZalo from "./PopupZalo";

const ProductInfo = ({ product, qty, setQty, addToCart, buyNow }) => {

  /* ==============================
      STATE POPUP ZALO — PHẢI ĐỂ TRÊN ĐẦU
  ============================== */
  const [openPopup, setOpenPopup] = useState(false);

  /* ==============================
      XÁC ĐỊNH SỐ LƯỢNG TỐI ĐA — CŨNG PHẢI NẰM TRÊN
  ============================== */
  const getMaxQty = (product) => {
    // Giá cao > 1 triệu → chỉ cho 1
    if (product?.price > 1000000) return 1;

    // Hoa khai trương → tối đa 2
    if (
      product?.category?.name?.toLowerCase().includes("khai trương") ||
      product?.name?.toLowerCase().includes("khai trương")
    ) {
      return 2;
    }

    // Hoa bó bình thường → tối đa 3
    return 3;
  };

  const maxQty = product ? getMaxQty(product) : 1;

  /* ==============================
      NẾU CHƯA CÓ PRODUCT — RETURN NGAY
  ============================== */
  if (!product) return null;

  /* ==============================
      HÀM XỬ LÝ TĂNG GIẢM
  ============================== */
  const decreaseQty = () => {
    if (qty > 1) setQty(qty - 1);
  };

  const increaseQty = () => {
    if (qty < maxQty) setQty(qty + 1);
    else setOpenPopup(true);
  };

  /* ==============================
      THÊM GIỎ / MUA NGAY
  ============================== */
  const handleAddToCart = () => {
    if (qty > maxQty) {
      setOpenPopup(true);
      return;
    }
    addToCart();
  };

  const handleBuyNow = () => {
    if (qty > maxQty) {
      setOpenPopup(true);
      return;
    }
    buyNow();
  };

  return (
    <div className="flex flex-col h-full justify-between">

      {/* TÊN SẢN PHẨM */}
      <h1 className="text-[22px] md:text-[24px] font-bold text-[#4b2c35] leading-snug">
        {product.name}
      </h1>

      {/* GIÁ */}
      <p className="text-pink-600 font-semibold text-[24px] md:text-[26px] mt-3">
        {(product.discountPrice || product.price).toLocaleString()}₫
      </p>

      {/* ĐÃ BÁN – CÒN */}
      <p className="text-[13px] text-gray-500 mt-1">
        Đã bán: {product.sold || 0} — Còn: {product.countInStock || 0}
      </p>

      {/* SỐ LƯỢNG */}
      <div className="mt-6">
        <p className="text-[15px] font-semibold text-[#4b2c35] mb-2">
          Số lượng (Tối đa: {maxQty})
        </p>

        <div className="flex items-center gap-4">
          <button
            onClick={decreaseQty}
            className="w-9 h-9 flex items-center justify-center rounded-full border border-gray-300 hover:bg-gray-100 transition"
          >
            -
          </button>

          <span className="text-[15px] font-medium">{qty}</span>

          <button
            onClick={increaseQty}
            className="w-9 h-9 flex items-center justify-center rounded-full border border-gray-300 hover:bg-gray-100 transition"
          >
            +
          </button>
        </div>
      </div>

      {/* NÚT */}
      <div className="flex gap-4 mt-8">
        <button
          className="px-6 py-3 rounded-full text-[15px] font-semibold bg-pink-200 text-pink-700 hover:bg-pink-300 transition shadow"
          onClick={handleAddToCart}
        >
          Thêm vào giỏ
        </button>

        <button
          className="px-6 py-3 rounded-full text-[15px] font-semibold bg-pink-600 text-white hover:bg-pink-700 transition shadow"
          onClick={handleBuyNow}
        >
          Mua ngay
        </button>
      </div>

      {/* POPUP ZALO */}
      <PopupZalo
        open={openPopup}
        onClose={() => setOpenPopup(false)}
        maxQty={maxQty}
      />

      
    </div>
    
  );
};

export default ProductInfo;
